sql:
SELECT COUNT(profile_id) AS profile_count
FROM profiles
WHERE created_by = 1 AND app_id = 1;

SELECT COUNT(DISTINCT app_id) AS distinct_applications_count
FROM applications
WHERE maintainer_id = 0;

SELECT DISTINCT app_name
FROM applications
WHERE status = 'active';

SELECT COUNT(DISTINCT app_id) AS app_count
FROM applications
WHERE created_at BETWEEN '2023-04-01' AND '2023-04-30';

SELECT app_id, COUNT(profile_id) AS number_of_profiles
FROM profiles
GROUP BY app_id;

SELECT access_date, COUNT(DISTINCT user_id) AS unique_user_access_count
FROM access_logs
GROUP BY access_date;

SELECT app_name
FROM applications
WHERE app_id = 1;

SELECT AVG(performance_metrics) AS average_performance_metrics
FROM profiles
WHERE profile_date BETWEEN date('now', '-30 days') AND date('now');

external_knowledge:
- "ships" refers to the unique programming models;
- "sails have been tested in the waters of performance more than once" signifies that the models have more than one associated profile;
- "average depth of the waters they have navigated through" represents the average performance metrics.

